from dataclasses import dataclass, field
from datetime import date
from typing import Optional

@dataclass
class PostLaunchObservation:
    metric_id: str
    week_number: int        # weeks since launch (1-indexed)
    value: float
    observed_at: date
    claude_usage_pct: float  # what % of tasks used Claude that week (0–100)

@dataclass
class BenefitTracker:
    initiative_id: str
    initiative_name: str
    launch_date: date
    baseline_mean: dict[str, float]    # metric_id → baseline value
    targets: dict[str, float]          # metric_id → post-launch target
    directions: dict[str, str]         # metric_id → "lower_is_better" | "higher_is_better"
    observations: list[PostLaunchObservation] = field(default_factory=list)

    def weeks_live(self, as_of: date) -> int:
        return max(0, (as_of - self.launch_date).days // 7)

    def latest_for(self, metric_id: str) -> Optional[PostLaunchObservation]:
        obs = [o for o in self.observations if o.metric_id == metric_id]
        return max(obs, key=lambda o: o.week_number) if obs else None

    def improvement_pct(self, metric_id: str) -> Optional[float]:
        latest = self.latest_for(metric_id)
        base = self.baseline_mean.get(metric_id)
        if latest is None or base is None or base == 0:
            return None
        direction = self.directions.get(metric_id, "lower_is_better")
        if direction == "lower_is_better":
            return (base - latest.value) / base * 100
        return (latest.value - base) / base * 100

    def target_met(self, metric_id: str) -> Optional[bool]:
        latest = self.latest_for(metric_id)
        target = self.targets.get(metric_id)
        if latest is None or target is None:
            return None
        direction = self.directions.get(metric_id, "lower_is_better")
        if direction == "lower_is_better":
            return latest.value <= target
        return latest.value >= target
